### Setting Up HttpClient

Import `HttpClientModule` in your app module (or use `provideHttpClient()` with standalone):

```typescript
// NgModule approach
import { HttpClientModule } from '@angular/common/http';

@NgModule({
  imports: [HttpClientModule]
})
export class AppModule { }

// Standalone approach
import { provideHttpClient } from '@angular/common/http';

bootstrapApplication(AppComponent, {
  providers: [provideHttpClient()]
});
```

### Making HTTP Requests

Inject `HttpClient` into your service:

```typescript
@Injectable({ providedIn: 'root' })
export class ApiService {
  constructor(private http: HttpClient) { }

  // GET
  getUsers(): Observable<User[]> {
    return this.http.get<User[]>('https://api.example.com/users');
  }

  // POST
  createUser(user: User): Observable<User> {
    return this.http.post<User>('https://api.example.com/users', user);
  }

  // PUT
  updateUser(id: number, user: User): Observable<User> {
    return this.http.put<User>(`https://api.example.com/users/${id}`, user);
  }

  // DELETE
  deleteUser(id: number): Observable<void> {
    return this.http.delete<void>(`https://api.example.com/users/${id}`);
  }
}
```

### Typed Responses

Angular HTTP methods are generic — pass the expected response type:
```typescript
this.http.get<User[]>('/api/users')       // returns Observable<User[]>
this.http.get<User>('/api/users/1')        // returns Observable<User>
this.http.get('/api/users', { responseType: 'text' })  // returns Observable<string>
```

### Query Parameters and Headers

```typescript
import { HttpParams, HttpHeaders } from '@angular/common/http';

const params = new HttpParams()
  .set('page', '1')
  .set('limit', '10');

const headers = new HttpHeaders()
  .set('Authorization', `Bearer ${token}`)
  .set('Content-Type', 'application/json');

this.http.get<User[]>('/api/users', { params, headers });
```

### Error Handling

Use `catchError` from RxJS:

```typescript
import { catchError, throwError } from 'rxjs';

getUsers(): Observable<User[]> {
  return this.http.get<User[]>('/api/users').pipe(
    catchError((error: HttpErrorResponse) => {
      console.error('API error:', error.message);
      return throwError(() => new Error('Failed to load users'));
    })
  );
}
```

### Full Service Example

```typescript
@Injectable({ providedIn: 'root' })
export class UserService {
  private apiUrl = 'https://api.example.com/users';

  constructor(private http: HttpClient) { }

  getAll(): Observable<User[]> {
    return this.http.get<User[]>(this.apiUrl).pipe(
      catchError(this.handleError)
    );
  }

  private handleError(error: HttpErrorResponse) {
    const msg = error.error instanceof ErrorEvent
      ? `Client error: ${error.error.message}`
      : `Server error: ${error.status}`;
    return throwError(() => new Error(msg));
  }
}
```

